import React, { useState, useMemo } from "react";
import { 
  theme, 
  Typography, 
  Table, 
  Button, 
  Space, 
  Select, 
  DatePicker,
  Card,
  Tag,
  Statistic,
  message,
  Badge
} from "antd";
import { 
  SearchOutlined, 
  FileExcelOutlined,
  DashboardOutlined,
  TableOutlined,
  BarChartOutlined,
  ArrowUpOutlined,
  ArrowDownOutlined
} from "@ant-design/icons";
import { useI18n } from "@/framework/i18n/hooks";
import { PLANTS, mockSensors } from "../../dashboard/data/mockData";
import EChart from "@/framework/components/Chart/EChart"; // Use Common Component
import dayjs from "dayjs";

const { Title } = Typography;
const { useToken } = theme;
const { Option } = Select;
const { RangePicker } = DatePicker;

interface SensorHistoryData {
  key: string;
  plantName: string;
  sensorName: string;
  address: string;
  value: string;
  numericValue: number;
  time: string;
  remark: string;
  plantId: number;
  sensorId: number;
}

const allMockHistory: SensorHistoryData[] = Array.from({ length: 300 }, (_, i) => {
  const sensor = mockSensors[i % mockSensors.length];
  const plant = PLANTS.find(p => p.id === sensor.plantId);
  const nv = sensor.value + (Math.random() * 10 - 5);
  return {
    key: i.toString(),
    plantName: plant?.name || `Plant ${sensor.plantId}`,
    sensorName: sensor.name,
    address: "서울 구로구 디지털로 12-3",
    value: `${nv.toFixed(1)}${sensor.unit || ""}`,
    numericValue: nv,
    time: dayjs().subtract(i * 15, "minute").format("YYYY-MM-DD HH:mm:ss"),
    remark: "-",
    plantId: sensor.plantId,
    sensorId: sensor.id
  };
});

export default function SensorHistory() {
  const { token } = useToken();
  const { t } = useI18n(["history"]);
  
  const [filterPlant, setFilterPlant] = useState<string>("all");
  const [filterSensor, setFilterSensor] = useState<string>("all");
  const [filterDates, setFilterDates] = useState<any>([dayjs().subtract(7, "day"), dayjs()]);
  
  const [filteredData, setFilteredData] = useState<SensorHistoryData[]>(allMockHistory);
  const [viewMode, setViewMode] = useState<"table" | "chart">("table");

  const handleSearch = () => {
    let result = [...allMockHistory];
    if (filterPlant !== "all") result = result.filter(it => it.plantId === Number(filterPlant));
    if (filterSensor !== "all") result = result.filter(it => it.sensorId === Number(filterSensor));
    if (filterDates && filterDates.length === 2) {
      const start = filterDates[0].startOf("day");
      const end = filterDates[1].endOf("day");
      result = result.filter(it => {
        const time = dayjs(it.time);
        return time.isAfter(start) && time.isBefore(end);
      });
    }
    setFilteredData(result);
    message.success(t("sensor.filters.search_success", { count: result.length }));
  };

  const sensorStats = useMemo(() => {
    if (filteredData.length === 0) return { avg: 0, max: 0, min: 0 };
    const avg = filteredData.reduce((acc, it) => acc + it.numericValue, 0) / filteredData.length;
    const max = Math.max(...filteredData.map(it => it.numericValue));
    const min = Math.min(...filteredData.map(it => it.numericValue));
    return { avg, max, min };
  }, [filteredData]);

  const trendOption = useMemo(() => {
    const displayData = [...filteredData].slice(0, 50).reverse();
    const times = displayData.map(it => it.time.split(" ")[1]);
    const values = displayData.map(it => it.numericValue);

    return {
      tooltip: { trigger: "axis" },
      grid: { left: "3%", right: "4%", bottom: "3%", containLabel: true },
      xAxis: { type: "category", boundaryGap: false, data: times },
      yAxis: { type: "value", scale: true },
      series: [
        {
          name: t("sensor.columns.value"),
          type: "line",
          smooth: true,
          areaStyle: {
            color: {
              type: "linear", x: 0, y: 0, x2: 0, y2: 1,
              colorStops: [{ offset: 0, color: token.colorPrimary }, { offset: 1, color: "transparent" }]
            }
          },
          lineStyle: { width: 3, color: token.colorPrimary },
          symbol: "none",
          data: values
        }
      ]
    };
  }, [filteredData, token, t]);

  const columns = [
    { title: t("sensor.columns.plant"), dataIndex: "plantName", key: "plantName", width: 170 },
    { title: t("sensor.columns.sensor"), dataIndex: "sensorName", key: "sensorName", ellipsis: true },
    { title: t("sensor.columns.address"), dataIndex: "address", key: "address", width: 280, ellipsis: true },
    { title: t("sensor.columns.value"), dataIndex: "value", key: "value", width: 120, align: "center" as const, render: (val: string) => <Tag color="cyan" style={{ borderRadius: 12, fontWeight: 700, padding: "2px 10px" }}>{val}</Tag> },
    { title: t("sensor.columns.time"), dataIndex: "time", key: "time", width: 180 },
    { title: t("sensor.columns.remark"), dataIndex: "remark", key: "remark", width: 100 },
  ];

  return (
    <div style={{ padding: "20px", background: token.colorBgLayout, minHeight: "100%", display: "flex", flexDirection: "column", gap: 20 }}>
      <Card styles={{ body: { padding: "12px 24px" } }} style={{ border: `1px solid ${token.colorBorderSecondary}` }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 16 }}>
          <Space size="middle">
            <Select value={filterPlant} onChange={setFilterPlant} style={{ width: 160, height: 40 }}><Option value="all">{t("sensor.filters.plant_all")}</Option>{PLANTS.map(p => <Option key={p.id} value={p.id.toString()}>{p.name}</Option>)}</Select>
            <Select value={filterSensor} onChange={setFilterSensor} style={{ width: 180, height: 40 }}><Option value="all">{t("sensor.filters.sensor_all")}</Option>{mockSensors.slice(0, 20).map(s => <Option key={s.id} value={s.id.toString()}>{s.name}</Option>)}</Select>
            <RangePicker value={filterDates} onChange={setFilterDates} style={{ height: 40 }} />
          </Space>
          <Space>
            <Button type="primary" icon={<SearchOutlined />} onClick={handleSearch} style={{ height: 40, width: 100 }}>{t("sensor.filters.search")}</Button>
            <Button icon={<FileExcelOutlined />} style={{ height: 40 }}>{t("sensor.filters.excel")}</Button>
            <Space.Compact><Button icon={<TableOutlined />} type={viewMode === "table" ? "primary" : "default"} onClick={() => setViewMode("table")} /><Button icon={<BarChartOutlined />} type={viewMode === "chart" ? "primary" : "default"} onClick={() => setViewMode("chart")} /></Space.Compact>
          </Space>
        </div>
      </Card>

      <div style={{ flex: 1, background: token.colorBgContainer, borderRadius: token.borderRadiusLG, border: `1px solid ${token.colorBorderSecondary}`, overflow: "hidden" }}>
        <div style={{ padding: "16px 24px", borderBottom: `1px solid ${token.colorBorderSecondary}`, display: "flex", alignItems: "center", gap: 10 }}>
          <DashboardOutlined style={{ fontSize: 20, color: token.colorPrimary }} /><Title level={4} style={{ margin: 0 }}>{t("sensor.title")}</Title>
          <Badge count={filteredData.length} overflowCount={999} style={{ backgroundColor: token.colorInfo, marginLeft: 8 }} />
        </div>
        
        {viewMode === "table" ? (
          <Table columns={columns} dataSource={filteredData} pagination={{ pageSize: 15 }} scroll={{ y: "calc(100vh - 380px)" }} />
        ) : (
          <div style={{ padding: 24, display: "flex", flexDirection: "column", gap: 24 }}>
             <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 24 }}>
                <Card><Statistic title={t("sensor.stats.avg")} value={sensorStats.avg} precision={2} valueStyle={{ color: token.colorPrimary }} prefix={<DashboardOutlined />} /></Card>
                <Card><Statistic title={t("sensor.stats.max")} value={sensorStats.max} precision={1} valueStyle={{ color: token.colorError }} prefix={<ArrowUpOutlined />} /></Card>
                <Card><Statistic title={t("sensor.stats.min")} value={sensorStats.min} precision={1} valueStyle={{ color: token.colorInfo }} prefix={<ArrowDownOutlined />} /></Card>
             </div>
             <Card title={t("sensor.stats.trend_title")}>
                <EChart option={trendOption} style={{ height: 400, width: "100%" }} />
             </Card>
          </div>
        )}
      </div>
    </div>
  );
}
